// Utility functions
function generateRefreshToken() {
  return crypto.randomBytes(64).toString('hex');
}

function generateAuthorizationCode() {
  return crypto.randomBytes(32).toString('hex');
}

function generateAccessToken(userId, clientId, scopes) {
  return jwt.sign(
    {
      sub: userId,
      client_id: clientId,
      scopes: scopes,
      type: 'access_token',
    },
    CONFIG.JWT_SECRET,
    { expiresIn: CONFIG.ACCESS_TOKEN_EXPIRY }
  );
}

// Store refresh token in Redis with 1-year TTL
async function storeRefreshToken(refreshToken, tokenData) {
  const key = `refresh_token:${refreshToken}`;
  const data = JSON.stringify({
    ...tokenData,
    createdAt: new Date().toISOString(),
    expiresAt: new Date(Date.now() + CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS * 1000).toISOString(),
  });

  await redisSet(key, data, 'EX', CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS);

  // Track refresh tokens per user for management/revocation
  const userTokensKey = `user_refresh_tokens:${tokenData.userId}`;
  await redisSAdd(userTokensKey, refreshToken);
  await redisExpire(userTokensKey, CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS);

  return true;
}

// Retrieve refresh token from Redis
async function getRefreshToken(refreshToken) {
  const key = `refresh_token:${refreshToken}`;
  const data = await redisGet(key);

  if (!data) {
    return null;
  }

  return JSON.parse(data);
}

// Revoke a specific refresh token
async function revokeRefreshToken(refreshToken) {
  const tokenData = await getRefreshToken(refreshToken);
  if (tokenData) {
    const userTokensKey = `user_refresh_tokens:${tokenData.userId}`;
    await redisSRem(userTokensKey, refreshToken);
  }
  const key = `refresh_token:${refreshToken}`;
  await redisDel(key);
}

// Revoke all refresh tokens for a user
async function revokeAllUserRefreshTokens(userId) {
  const userTokensKey = `user_refresh_tokens:${userId}`;
  const tokens = await redisSMembers(userTokensKey);

  if (tokens && tokens.length > 0) {
    const pipeline = tokens.map((token) => `refresh_token:${token}`);
    for (const key of pipeline) {
      await redisDel(key);
    }
  }

  await redisDel(userTokensKey);
}

// Store authorization code
async function storeAuthorizationCode(code, codeData) {
  const key = `auth_code:${code}`;
  const data = JSON.stringify({
    ...codeData,
    createdAt: new Date().toISOString(),
  });
  // Authorization codes expire in 10 minutes
  await redisSet(key, data, 'EX', 600);
}

// Retrieve and consume authorization code
async function consumeAuthorizationCode(code) {
  const key = `auth_code:${code}`;
  const data = await redisGet(key);

  if (!data) {
    return null;
  }

  // Delete the code after retrieval (single use)
  await redisDel(key);
  return JSON.parse(data);
}

// Middleware: Authenticate client
async function authenticateClient(req, res, next) {
  let clientId, clientSecret;

  // Check Authorization header (Basic auth)
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const parts = decoded.split(':');
    clientId = decodeURIComponent(parts[0]);
    clientSecret = decodeURIComponent(parts.slice(1).join(':'));
  }

  // Check body parameters
  if (!clientId) {
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  if (!clientId || !clientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed. Provide client_id and client_secret.',
    });
  }

  const client = oauthClients.get(clientId);
  if (!client) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Unknown client.',
    });
  }

  const validSecret = await bcrypt.compare(clientSecret, client.clientSecretHash);
  if (!validSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Invalid client credentials.',
    });
  }

  req.oauthClient = client;
  next();
}

// Middleware: Authenticate access token (for protected resources)
function authenticateAccessToken(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Access token is required.',
    });
  }

  const token = authHeader.slice(7);

  try {
    const decoded = jwt.verify(token, CONFIG.JWT_SECRET);
    if (decoded.type !== 'access_token') {
      throw new Error('Invalid token type');
    }
    req.user = decoded;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({
        error: 'invalid_token',
        error_description: 'Access token has expired.',
      });
    }
    return res.status(401).json({
      error: 'invalid_token',
      error_description: 'Invalid access token.',
    });
  }
}

