// POST /authorize - Process authorization
app.post('/authorize', async (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state, username, password, action } = req.body;

  const client = oauthClients.get(client_id);
  if (!client) {
    return res.status(400).json({
      error: 'invalid_client',
      error_description: 'Unknown client_id.',
    });
  }

  const finalRedirectUri = redirect_uri || client.redirectUris[0];

  if (action === 'deny') {
    const redirectUrl = new URL(finalRedirectUri);
    redirectUrl.searchParams.set('error', 'access_denied');
    redirectUrl.searchParams.set('error_description', 'User denied the authorization request.');
    if (state) redirectUrl.searchParams.set('state', state);
    return res.redirect(redirectUrl.toString());
  }

  // Authenticate user
  let authenticatedUser = null;
  for (const [id, user] of users) {
    if (user.username === username) {
      const validPassword = await bcrypt.compare(password, user.passwordHash);
      if (validPassword) {
        authenticatedUser = user;
      }
      break;
    }
  }

  if (!authenticatedUser) {
    return res.status(401).send(`
      <html><body>
        <h2>Authentication Failed</h2>
        <p>Invalid username or password.</p>
        <a href="javascript:history.back()">Try again</a>
      </body></html>
    `);
  }

  // Validate scopes
  const requestedScopes = scope ? scope.split(' ').filter(Boolean) : ['read'];
  const validScopes = requestedScopes.filter((s) => client.scopes.includes(s));

  // Generate authorization code
  const authCode = generateAuthorizationCode();
  await storeAuthorizationCode(authCode, {
    userId: authenticatedUser.id,
    clientId: client_id,
    redirectUri: finalRedirectUri,
    scopes: validScopes,
  });

  // Redirect with authorization code
  const redirectUrl = new URL(finalRedirectUri);
  redirectUrl.searchParams.set('code', authCode);
  if (state) redirectUrl.searchParams.set('state', state);
  res.redirect(redirectUrl.toString());
});

// POST /token - Token endpoint
app.post('/token', authenticateClient, async (req, res) => {
  const { grant_type } = req.body;
  const client = req.oauthClient;

  if (!client.grants.includes(grant_type)) {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: `Grant type "${grant_type}" is not supported for this client.`,
    });
  }

  switch (grant_type) {
    case 'authorization_code':
      return handleAuthorizationCodeGrant(req, res, client);
    case 'password':
      return handlePasswordGrant(req, res, client);
    case 'refresh_token':
      return handleRefreshTokenGrant(req, res, client);
    default:
      return res.status(400).json({
        error: 'unsupported_grant_type',
        error_description: `Grant type "${grant_type}" is not supported.`,
      });
  }
});

// Handle Authorization Code Grant
async function handleAuthorizationCodeGrant(req, res, client) {
  const { code, redirect_uri } = req.body;

  if (!code) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Authorization code is required.',
    });
  }

  const codeData = await consumeAuthorizationCode(code);
  if (!codeData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid or expired authorization code.',
    });
  }

  // Verify client matches
  if (codeData.clientId !== client.clientId) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client.',
    });
  }

  // Verify redirect_uri matches
  if (redirect_uri && redirect_uri !== codeData.redirectUri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Redirect URI mismatch.',
    });
  }

  // Generate tokens
  const accessToken = generateAccessToken(codeData.userId, client.clientId, codeData.scopes);
  const refreshToken = generateRefreshToken();

  // Store refresh token in Redis with 1-year TTL (reusable, no rotation)
  await storeRefreshToken(refreshToken, {
    userId: codeData.userId,
    clientId: client.clientId,
    scopes: codeData.scopes,
    grantType: 'authorization_code',
  });

  console.log(`[TOKEN] Issued access + refresh token for user ${codeData.userId} via authorization_code`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900, // 15 minutes in seconds
    refresh_token: refreshToken,
    refresh_token_expires_in: CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS,
    scope: codeData.scopes.join(' '),
  });
}

// Handle Resource Owner Password Credentials Grant
async function handlePasswordGrant(req, res, client) {
  const { username, password, scope } = req.body;

  if (!username || !password) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Username and password are required.',
    });
  }

  // Authenticate user
  let authenticatedUser = null;
  for (const [id, user] of users) {
    if (user.username === username) {
      const validPassword = await bcrypt.compare(password, user.passwordHash);
      if (validPassword) {
        authenticatedUser = user;
      }
      break;
    }
  }

  if (!authenticatedUser) {
    return res.status(401).json({
      error: 'invalid_grant',
      error_description: 'Invalid username or password.',
    });
  }

  // Validate scopes
  const requestedScopes = scope ? scope.split(' ').filter(Boolean) : ['read'];
  const validScopes = requestedScopes.filter((s) => client.scopes.includes(s));

  if (validScopes.length === 0) {
    return res.status(400).json({
      error: 'invalid_scope',
      error_description: 'No valid scopes requested.',
    });
  }

  // Generate tokens
  const accessToken = generateAccessToken(authenticatedUser.id, client.clientId, validScopes);
  const refreshToken = generateRefreshToken();

  // Store refresh token in Redis with 1-year TTL (reusable, no rotation)
  await storeRefreshToken(refreshToken, {
    userId: authenticatedUser.id,
    clientId: client.clientId,
    scopes: validScopes,
    grantType: 'password',
  });

  console.log(`[TOKEN] Issued access + refresh token for user ${authenticatedUser.id} via password grant`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900,
    refresh_token: refreshToken,
    refresh_token_expires_in: CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS,
    scope: validScopes.join(' '),
  });
}

// Handle Refresh Token Grant (reuse without rotation)
async function handleRefreshTokenGrant(req, res, client) {
  const { refresh_token, scope } = req.body;

  if (!refresh_token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Refresh token is required.',
    });
  }

  // Retrieve refresh token from Redis
  const tokenData = await getRefreshToken(refresh_token);

  if (!tokenData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid or expired refresh token.',
    });
  }

  // Verify client matches
  if (tokenData.clientId !== client.clientId) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client.',
    });
  }

  // Check if user still exists
  const user = users.get(tokenData.userId);
  if (!user) {
    // Revoke the token if user no longer exists
    await revokeRefreshToken(refresh_token);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'User associated with this refresh token no longer exists.',
    });
  }

  // Handle scope narrowing (can request equal or fewer scopes)
  let grantedScopes = tokenData.scopes;
  if (scope) {
    const requestedScopes = scope.split(' ').filter(Boolean);
    const narrowedScopes = requestedScopes.filter((s) => tokenData.scopes.includes(s));
    if (narrowedScopes.length === 0) {
      return res.status(400).json({
        error: 'invalid_scope',
        error_description: 'Requested scopes exceed the original grant.',
      });
    }
    grantedScopes = narrowedScopes;
  }

  // Generate new access token only (refresh token is REUSED, not rotated)
  const accessToken = generateAccessToken(tokenData.userId, client.clientId, grantedScopes);

  // NOTE: The same refresh token is reused - no rotation per user's requirement
  // The original refresh token remains valid in Redis with its original TTL

  console.log(`[TOKEN] Reissued access token for user ${tokenData.userId} using existing refresh token (no rotation)`);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 900,
    refresh_token: refresh_token, // Same refresh token returned (reused)
    refresh_token_expires_in: Math.max(
      0,
      Math.floor((new Date(tokenData.expiresAt).getTime() - Date.now()) / 1000)
    ),
    scope: grantedScopes.join(' '),
  });
}

// POST /revoke - Token revocation endpoint (RFC 7009)
app.post('/revoke', authenticateClient, async (req, res) => {
  const { token, token_type_hint } = req.body;

  if (!token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Token is required.',
    });
  }

  // Try to revoke as refresh token
  if (!token_type_hint || token_type_hint === 'refresh_token') {
    const tokenData = await getRefreshToken(token);
    if (tokenData) {
      // Verify client owns this token
      if (tokenData.clientId === req.oauthClient.clientId) {
        await revokeRefreshToken(token);
        console.log(`[REVOKE] Refresh token revoked for user ${tokenData.userId}`);
      }
    }
  }

  // RFC 7009: Always respond with 200, even if token was invalid
  res.status(200).json({ revoked: true });
});

// POST /revoke-all - Revoke all refresh tokens for a user (custom endpoint)
app.post('/revoke-all', authenticateAccessToken, async (req, res) => {
  const userId = req.user.sub;

  await revokeAllUserRefreshTokens(userId);
  console.log(`[REVOKE] All refresh tokens revoked for user ${userId}`);

  res.json({
    message: 'All refresh tokens have been revoked.',
    user_id: userId,
  });
});

// GET /userinfo - Protected resource (user info)
app.get('/userinfo', authenticateAccessToken, (req, res) => {
  const user = users.get(req.user.sub);

  if (!user) {
    return res.status(404).json({
      error: 'user_not_found',
      error_description: 'User not found.',
    });
  }

  const userInfo = {
    sub: user.id,
    username: user.username,
    email: user.email,
  };

  // Only include email if 'profile' scope is granted
  if (!req.user.scopes || !req.user.scopes.includes('profile')) {
    delete userInfo.email;
  }

  res.json(userInfo);
});

// GET /token-info - Introspection-like endpoint
app.post('/introspect', authenticateClient, async (req, res) => {
  const { token, token_type_hint } = req.body;

  if (!token) {
    return res.status(400).json({ active: false });
  }

  // Check if it's an access token
  if (!token_type_hint || token_type_hint === 'access_token') {
    try {
      const decoded = jwt.verify(token, CONFIG.JWT_SECRET);
      if (decoded.type === 'access_token') {
        return res.json({
          active: true,
          token_type: 'access_token',
          sub: decoded.sub,
          client_id: decoded.client_id,
          scope: decoded.scopes ? decoded.scopes.join(' ') : '',
          exp: decoded.exp,
          iat: decoded.iat,
        });
      }
    } catch (err) {
      // Token is invalid or expired
      if (token_type_hint === 'access_token') {
        return res.json({ active: false });
      }
    }
  }

  // Check if it's a refresh token
  if (!token_type_hint || token_type_hint === 'refresh_token') {
    const tokenData = await getRefreshToken(token);
    if (tokenData) {
      return res.json({
        active: true,
        token_type: 'refresh_token',
        sub: tokenData.userId,
        client_id: tokenData.clientId,
        scope: tokenData.scopes ? tokenData.scopes.join(' ') : '',
        exp: Math.floor(new Date(tokenData.expiresAt).getTime() / 1000),
        iat: Math.floor(new Date(tokenData.createdAt).getTime() / 1000),
      });
    }
  }

  res.json({ active: false });
});

